# Compute similarity metrics for the candidate list 'cands' (size ~60)
def lcs_len(a,b):
    # returns length of longest common subsequence (not substring) using DP; small strings so ok
    n,m = len(a), len(b)
    dp = [[0]*(m+1) for _ in range(n+1)]
    for i in range(1,n+1):
        ai = a[i-1]
        row = dp[i]
        prev_row = dp[i-1]
        for j in range(1,m+1):
            if ai == b[j-1]:
                row[j] = prev_row[j-1] + 1
            else:
                row[j] = max(prev_row[j], row[j-1])
    return dp[n][m]

def lcs_ratio(a,b):
    l = lcs_len(a,b)
    return l / max(len(a),1), l / max(len(b),1), l / max(len(a), len(b))

